package bind

import (
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
)

// MTU accounting for the bonded datapath.
//
// A tunnelled application packet is wrapped in four nested layers before it hits
// the wire, each adding fixed overhead:
//
//		[ IP | UDP | outer DATA frame | WG transport | inner IP payload ]
//		  \___ IPv4UDPOverhead ___/   \_DataOverhead_/\_WGTransportOverhead_/
//
//	  - IP + UDP: the underlay carrying our outer datagram.
//	  - outer DATA frame: the bonding codec's nonce + DATA header (frame.DataOverhead).
//	  - WG transport: WireGuard's own data-message header + Poly1305 tag.
//
// InnerMTU sizes the TUN so a full-MTU inner packet, once wrapped in all four
// layers, still fits the path MTU without IP fragmentation. Fragmentation must be
// avoided: a fragment lost on a lossy WAN drops the whole datagram, and PMTUD
// black holes (ICMP "fragmentation needed" filtered by a middlebox) silently stall
// the tunnel. See docs/p1-mtu.md for the derivation and the MSS-clamping guidance
// that keeps TCP inside this budget.
const (
	// DefaultPathMTU is the assumed underlay path MTU when none is measured. 1500
	// is the near-universal Ethernet/most-broadband figure; deployments on links
	// with a smaller MTU (some LTE/PPPoE uplinks) must lower it.
	DefaultPathMTU = 1500

	// IPv4UDPOverhead is the outer IPv4 (20) + UDP (8) header cost. IPv4 is the
	// conservative default here; an IPv6 underlay costs 20 bytes more (see
	// IPv6UDPOverhead) so sizing for IPv4 and running over IPv6 only wastes a few
	// bytes, never fragments.
	IPv4UDPOverhead = 20 + 8

	// IPv6UDPOverhead is the outer IPv6 (40) + UDP (8) header cost.
	IPv6UDPOverhead = 40 + 8

	// WGTransportOverhead is WireGuard's per-datagram data-message overhead: the
	// 16-byte transport header (msg type + reserved + receiver index + counter)
	// plus the 16-byte Poly1305 authentication tag. Amnezia junk PREFIXES add
	// further variable bytes on top; they are handled as best-effort headroom, not
	// subtracted here, because they are configurable and per-packet variable.
	WGTransportOverhead = 16 + 16
)

// FECParityMTUPenalty is the extra bytes a full-size FEC PARITY frame occupies on the
// wire over a DATA frame carrying the same-size inner payload (T24). A parity frame is
// nonce + PARITY header + shard payload, where the shard payload is the codec's length
// prefix + the FEC outer-seq prefix + the largest coded inner payload; a data frame is
// nonce + DATA header + that same inner payload. So the delta is:
//
//	(ParityOverhead + ShardFramingOverhead + fecSeqPrefixLen) - DataOverhead  ==  5 bytes.
//
// When FEC is enabled the inner MTU is reduced by this penalty so a full-MTU DATA frame
// AND its group's PARITY frame both fit the path MTU — otherwise parity exceeds the
// path MTU by exactly this much and IP-fragments or is EMSGSIZE/PMTUD-blackholed, which
// silently kills the very redundancy FEC exists to provide on bulk full-size traffic.
const FECParityMTUPenalty = frame.ParityOverhead + fec.ShardFramingOverhead + fecSeqPrefixLen - frame.DataOverhead

// InnerMTU returns the largest inner (TUN) MTU that avoids IP fragmentation over
// an IPv4 underlay of the given path MTU: pathMTU minus the IP+UDP, outer DATA
// frame, and WireGuard transport overheads. fecEnabled additionally reserves the
// parity-over-data delta so a full-size parity frame also fits (see
// FECParityMTUPenalty); pass false when FEC is off to keep the pre-T24 budget.
func InnerMTU(pathMTU int, fecEnabled bool) int {
	return pathMTU - IPv4UDPOverhead - frame.DataOverhead - WGTransportOverhead - fecPenalty(fecEnabled)
}

// InnerMTU6 is InnerMTU for an IPv6 underlay.
func InnerMTU6(pathMTU int, fecEnabled bool) int {
	return pathMTU - IPv6UDPOverhead - frame.DataOverhead - WGTransportOverhead - fecPenalty(fecEnabled)
}

// fecPenalty is the inner-MTU reduction to reserve for FEC parity, or 0 when FEC is
// off.
func fecPenalty(fecEnabled bool) int {
	if fecEnabled {
		return FECParityMTUPenalty
	}
	return 0
}

	// WeightRTTFloor floors RTT in the weight formula (must be > 0 under weighted).
	// Parsed from WeightRTTFloorRaw in normalize.
	WeightRTTFloor time.Duration `toml:"-"`
	// WeightRTTFloorRaw is the TOML Go-duration string form of WeightRTTFloor, e.g.
	// "1ms" (D43). Parsed in normalize; an unparseable value fails fast.
	WeightRTTFloorRaw string `toml:"weight_rtt_floor"`
	// WeightLossFloor floors the loss term under the square root (must be > 0 under
	// weighted).
	WeightLossFloor float64 `toml:"weight_loss_floor"`
}

// BDPSizing is a per-path pacing sizing derived from a MEASURED path, in the
// frame-selection-slot units the weighted scheduler pace uses (defect D22). It is the
// empirical alternative to the synthetic frame-count defaults: CapacityFPS replaces
// PerPathCapacityFPS and BurstFrames replaces PacingBurstFrames.
type BDPSizing struct {
	// CapacityFPS is the sustained per-path frame rate the measured bottleneck bandwidth
	// supports (the token-bucket refill rate and aggregation-gate denominator).
	CapacityFPS float64
	// BurstFrames is the bandwidth-delay product expressed in frames (bandwidth x RTT,
	// i.e. one RTT of in-flight frames): the token-bucket burst that absorbs one RTT of
	// jitter without building a standing queue.
	BurstFrames float64
}

// defaultAvgWireFrameBytes is the conservative average on-wire outer-frame size used
// when deriving the per-path pace from an operator-declared bandwidth at config load
// (T53): a full IPv4 path MTU, since a full-MTU DATA datagram occupies about one path
// MTU on the wire. It mirrors bind.DefaultPathMTU (1500) rather than importing it —
// internal/bind imports internal/config, so config cannot import bind without a cycle
// (the same mirror-with-cross-reference pattern as maxFECDeadline above). Sizing
// capacity with the full-MTU frame is the conservative floor: smaller average frames
// would yield a HIGHER frame rate, so this never over-paces a path.
const defaultAvgWireFrameBytes = 1500.0

// SizePacingFromBDP derives the weighted scheduler's per-path pacing parameters from a
// measured path instead of the synthetic frame-count default (defect D22). The shipped
// defaultPerPathCapacityFPS (10000, ~115 Mbit/s at full MTU) sits far above a realistic
// slow uplink, so the aggregation gate may never engage and — with pacing enabled — the
// pace never binds; deriving capacity from the measured bottleneck bandwidth fixes both.
//
// capacity_fps = bandwidth / (8 * avg wire frame bytes) — frames/s the link sustains.
// burst_frames = capacity_fps * RTT — one RTT of in-flight frames (equivalently
// BDP_bytes / avg wire frame bytes, since the bandwidth-delay product BDP = bandwidth * RTT).
//
// bandwidthBitsPerSec is the measured bottleneck bandwidth (bits/s), rtt the measured
// path RTT, and avgWireFrameBytes the average on-wire outer-frame size (a full-MTU
// datagram plus frame.DataOverhead is the conservative choice). It fails fast on a
// non-positive input rather than emitting a nonsensical (zero/negative/Inf) sizing.
func SizePacingFromBDP(bandwidthBitsPerSec float64, rtt time.Duration, avgWireFrameBytes float64) (BDPSizing, error) {
	if bandwidthBitsPerSec <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing bandwidth must be > 0 bit/s, got %g", bandwidthBitsPerSec)
	}
	if rtt <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing RTT must be > 0, got %s", rtt)
	}
	if avgWireFrameBytes <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing average wire frame size must be > 0 bytes, got %g", avgWireFrameBytes)
	}
	const bitsPerByte = 8.0

package frame

import (
	"crypto/hkdf"
	"crypto/hmac"
	"crypto/rand"
	"crypto/sha256"
	"encoding/binary"
	"errors"
	"fmt"

	"golang.org/x/crypto/chacha20"

	"github.com/7mind/wanbond/internal/config"
)

// Wire model (requirement-6 groundwork — no plaintext magic bytes, no fixed
// offsets). Every frame on the wire is:
//
//	nonce[nonceLen] || obf(body) [ || tag[tagLen] ]
//
//   - nonce is nonceLen fresh random bytes (high entropy, never constant).
//   - body is (kind byte || kind-specific header || opaque payload). It is
//     obfuscated by XOR with an XChaCha20 keystream derived from a PSK-bound
//     obfuscation subkey and the per-frame nonce, so the type discriminant and
//     header never sit at a constant offset — a byte-histogram over many random
//     encodings shows no constant byte position.
//   - tag is present ONLY for authenticated kinds (CONTROL, PROBE): an
//     Encrypt-then-MAC HMAC-SHA256 (truncated to tagLen) over nonce||obf(body)
//     keyed by a distinct PSK-bound auth subkey. Decode verifies it and rejects
//     tampered or PSK-mismatched frames. DATA and PARITY are unauthenticated by
//     design (DoS-grade forgery accepted — the inner WireGuard layer
//     authenticates the real payload); they carry no tag but are still
//     keystream-obfuscated so the no-fixed-offset property holds and the peer,
//     sharing the PSK, derives the same keystream to decode them.
//
// The two subkeys are derived from the PSK with HKDF-SHA256 under distinct info
// labels, so the obfuscation stream and the authentication MAC never share key
// material. All primitives are vetted (crypto/hkdf, x/crypto/chacha20,
// crypto/hmac) — no hand-rolled crypto.
//
// The outer-seq DATA field is this codec's OWN sequence space (see
// docs/p0-findings.md §6); it is never the inner WireGuard counter, and this
// codec never inspects the opaque WG payload (§4).

const (
	// nonceLen is the XChaCha20 nonce length carried in the clear at the head of
	// every frame.
	nonceLen = chacha20.NonceSizeX // 24
	// tagLen is the truncated HMAC-SHA256 authentication tag length appended to
	// authenticated frames.
	tagLen = 16
	// subkeyLen is the length of each HKDF-derived subkey.
	subkeyLen = 32

	infoObf  = "wanbond outer-frame obfuscation v1"
	infoAuth = "wanbond outer-frame authentication v1"
)

// DataOverhead is the number of bytes a KindData frame adds on top of its opaque
// payload on the wire: the clear nonce plus the DATA header (kind || outer-seq ||
// path-id || fec-group || fec-index || flags). DATA frames are unauthenticated
// (see the wire model above), so they carry no tag; this figure is therefore exact
// and is what the multipath Bind subtracts from the path MTU when sizing the inner
// tunnel (see internal/bind mtu.go). The fec-index byte is carried on every DATA
// frame — 0 and inert when FEC is disabled (T24) — so the codec's wire layout is
// invariant to the FEC toggle.
const DataOverhead = nonceLen + // clear nonce
	1 + // kind discriminant
	8 + // outer-seq (uint64)
	1 + // path-id (uint8)
	4 + // fec-group (uint32)
	1 + // fec-index (uint8): shard position within the FEC group (T24)
	1 // flags (uint8)

// ParityOverhead is the number of bytes a KindParity frame adds on top of its
// shard payload on the wire: the clear nonce plus the PARITY header (kind ||
// fec-group || parity-index || data-count || path-id). PARITY, like DATA, is
// unauthenticated and carries no tag, so this figure is exact. The multipath Bind
// uses it to size the FEC parity-overhead MTU penalty (T24): a full-size parity
// frame is 5 bytes larger on the wire than a full-size DATA frame carrying the same
// inner payload, so with FEC enabled the inner MTU is reduced so BOTH fit the path
// MTU without fragmentation (see internal/bind mtu.go).
const ParityOverhead = nonceLen + // clear nonce
	1 + // kind discriminant
	4 + // fec-group (uint32)
	2 + // parity-index (uint16)
	1 + // data-count (uint8)
	1 // path-id (uint8)

// Kind is the outer frame discriminant. Values are nonzero so a zeroed buffer
// never decodes to a valid kind.
type Kind uint8

const (
	// KindData wraps one opaque WireGuard datagram with multipath/FEC metadata.
	KindData Kind = 1
	// KindParity carries an FEC parity symbol for a fec-group.
	KindParity Kind = 2
	// KindProbe is an authenticated path-probe (RTT / liveness) frame.
	KindProbe Kind = 3
	// KindControl is an authenticated out-of-band control frame.
	KindControl Kind = 4
)

func (k Kind) valid() bool {
	return k == KindData || k == KindParity || k == KindProbe || k == KindControl
}

// authenticated reports whether frames of this kind append (and verify) a MAC.
func (k Kind) authenticated() bool {
	return k == KindProbe || k == KindControl
}

// Frame is the closed sum over the four outer frame kinds. The unexported
// marker method prevents other packages from adding kinds.
type Frame interface {
	// Kind returns the frame's discriminant.
	Kind() Kind
	// appendBody appends the plaintext body (kind byte || header || payload).
	appendBody(dst []byte) []byte
	isFrame()
}

// Data wraps a single opaque WireGuard datagram. OuterSeq is this codec's own
// sequence space (never the inner WG counter); PathID/FECGroup/FECIndex/Flags feed
// the multipath scheduler (T12), FEC (T14/T24), and resequencer (T18). FECIndex is
// the data shard's position within its FEC group (0..M-1); it is 0 and inert when
// FEC is disabled. The receiver reconstructs the FEC data-shard bytes as
// OuterSeq || Payload, so a shard recovered from parity carries its own outer-seq
// (T24) — no separate per-group base state is needed to resequence a recovered
// frame.
type Data struct {
	OuterSeq uint64
	PathID   uint8
	FECGroup uint32
	FECIndex uint8
	Flags    uint8
	Payload  []byte
}

// Parity carries one FEC parity symbol for a fec-group. DataCount is the group
// cardinality M (the number of data shards the parity protects); the decoder learns
// M from any surviving parity frame, so it must ride the wire (T24).
type Parity struct {
	FECGroup    uint32
	ParityIndex uint16
	DataCount   uint8
	PathID      uint8
	Payload     []byte
}

// Probe is an authenticated path probe used for RTT and liveness estimation.
//
// IsEcho is the request/response discriminant. A probe emitted by an originator
// (telemetry.Prober.SendProbe) carries IsEcho=false; the responder reflects it
// verbatim with IsEcho=true (telemetry.Reflector.Reflect). The two are otherwise
// byte-for-body-identical, so the receiving transport needs this bit to route an
// inbound frame: IsEcho=false is a peer probe to REFLECT, IsEcho=true is an echo
// of our own probe to FEED into that path's Prober. Marking the echo also breaks
// the otherwise-unbounded reflect-of-a-reflect loop (an echo is never reflected).
//
// SessionID is the originator's random per-boot session identity (T38, defect
// D12). It sits inside the MAC-covered body (adjacent to IsEcho), so an attacker
// can neither forge nor flip it. The responder reflects it verbatim. It TAGS the
// session (which boot the probe stream belongs to); on its own it is NOT proof of
// freshness (a captured probe carries a "never-seen" SessionID too), so the
// session-epoch reset is gated on the Challenge below, never on the SessionID
// merely being novel.
//
// Challenge is the responder-contributed freshness token (T38 redesign, defect
// D12). Like SessionID it lives inside obf(body) under the MAC, so it is both
// confidential (only a PSK holder can read it) and unforgeable. Its meaning is
// keyed by IsEcho:
//
//   - On an ECHO (IsEcho=true, emitted by the Reflector): Challenge is the
//     responder's CURRENT per-path issued challenge — a fresh random value the
//     originator must echo back to prove liveness.
//   - On a PROBE (IsEcho=false, emitted by the originator): Challenge is the last
//     issued challenge the originator learned from an echo (zero before it has
//     seen any). The responder adopts a new session epoch (resetting its
//     anti-replay high-water) ONLY when this equals its live issued challenge, so
//     a replayed probe — which can never carry the responder's current challenge —
//     can never seize the epoch or lock out the live peer.
type Probe struct {
	PathID         uint8
	ProbeSeq       uint64
	TimestampNanos int64
	IsEcho         bool
	SessionID      uint64
	Challenge      uint64
	Payload        []byte
}

// Control is an authenticated out-of-band control frame.
//
// Seq is a strictly-monotonic per-(peer, ControlType) sequence number: the
// freshness material the STATEFUL control-handling layer (telemetry.ControlGuard)
// uses to reject replays of a security-relevant control message (defect D4). The
// codec (Decode) verifies only the PSK HMAC and keeps no per-peer state, so a
// passively-captured valid control frame — e.g. a rekey — replays with a passing
// MAC; the downstream guard tracks a per-type high-water on Seq and drops the
// replay. Seq rides INSIDE obf(body) under the MAC (like Probe.ProbeSeq), so an
// attacker can neither read it nor forge/advance it to smuggle a replay past the
// guard.
type Control struct {
	ControlType uint8
	Seq         uint64
	Payload     []byte
}

func (Data) isFrame()    {}
func (Parity) isFrame()  {}
func (Probe) isFrame()   {}
func (Control) isFrame() {}

func (Data) Kind() Kind    { return KindData }
func (Parity) Kind() Kind  { return KindParity }
func (Probe) Kind() Kind   { return KindProbe }
func (Control) Kind() Kind { return KindControl }

func (f Data) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindData))
	dst = binary.BigEndian.AppendUint64(dst, f.OuterSeq)
	dst = append(dst, f.PathID)
	dst = binary.BigEndian.AppendUint32(dst, f.FECGroup)
	dst = append(dst, f.FECIndex)
	dst = append(dst, f.Flags)
	return append(dst, f.Payload...)
}

func (f Parity) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindParity))
	dst = binary.BigEndian.AppendUint32(dst, f.FECGroup)
	dst = binary.BigEndian.AppendUint16(dst, f.ParityIndex)
	dst = append(dst, f.DataCount)
	dst = append(dst, f.PathID)
	return append(dst, f.Payload...)
}

func (f Probe) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindProbe))
	dst = append(dst, f.PathID)
	dst = binary.BigEndian.AppendUint64(dst, f.ProbeSeq)
	dst = binary.BigEndian.AppendUint64(dst, uint64(f.TimestampNanos))
	dst = append(dst, boolByte(f.IsEcho))
	dst = binary.BigEndian.AppendUint64(dst, f.SessionID)
	dst = binary.BigEndian.AppendUint64(dst, f.Challenge)
	return append(dst, f.Payload...)
}

// boolByte encodes a bool as a single wire byte (0 or 1).
func boolByte(b bool) byte {
	if b {
		return 1
	}
	return 0
}

func (f Control) appendBody(dst []byte) []byte {
	dst = append(dst, byte(KindControl))
	dst = append(dst, f.ControlType)
	dst = binary.BigEndian.AppendUint64(dst, f.Seq)
	return append(dst, f.Payload...)
}

// ErrMalformed is returned by Decode for any input too short or structurally
// invalid to be a frame.
var ErrMalformed = errors.New("frame: malformed input")

// ErrAuth is returned by Decode when an authenticated frame fails its MAC check
// (tampered ciphertext or PSK mismatch).
var ErrAuth = errors.New("frame: authentication failed")

// Codec is a reusable, PSK-bound frame encoder/decoder. It derives the HKDF
// obfuscation and authentication subkeys ONCE at construction and reuses them
// (plus per-call scratch buffers) across every Encode/Decode, and it inits the
// XChaCha20 keystream exactly once per frame. This resolves defect D5: the old
// package-level Encode/Decode re-derived both subkeys with HKDF-SHA256 and
// double-init'd ChaCha20 (once in peekByte, once for the full body) on EVERY
// frame — prohibitive on the per-datagram datapath the multipath Bind drives.
//
// A Codec is NOT safe for concurrent use: its scratch buffers are shared across
// calls. Construct one per goroutine (the Bind gives each per-path receive loop
// its own Codec and guards the shared send Codec with the Bind mutex).
type Codec struct {
	obfKey     []byte
	authKey    []byte
	encScratch []byte // reused body buffer for Encode
	decScratch []byte // reused body buffer for Decode
}

// NewCodec derives the PSK-bound subkeys once and returns a reusable Codec. It
// fails only if the PSK is unset.
func NewCodec(psk config.Key) (*Codec, error) {
	obfKey, authKey, err := subkeys(psk)
	if err != nil {
		return nil, err
	}
	return &Codec{obfKey: obfKey, authKey: authKey}, nil
}

// Encode appends the wire encoding of f to dst and returns the extended slice,
// letting the caller reuse one buffer across sends (pass dst[:0]). It fails only
// if the system CSPRNG is unavailable.
func (c *Codec) Encode(dst []byte, f Frame) ([]byte, error) {
	// Build the plaintext body (kind || header || payload) in reusable scratch.
	c.encScratch = f.appendBody(c.encScratch[:0])
	body := c.encScratch

	start := len(dst)
	dst = append(dst, make([]byte, nonceLen)...)
	nonce := dst[start : start+nonceLen]
	if _, err := rand.Read(nonce); err != nil {
		return nil, fmt.Errorf("frame: read nonce: %w", err)
	}

	// Obfuscate the body in scratch, then append it; a single keystream init.
	obfuscate(c.obfKey, nonce, body)
	dst = append(dst, body...)

	if f.Kind().authenticated() {
		// After the append above, nonce and obfBody are contiguous in dst's
		// (possibly reallocated) backing array; tag over nonce||obfBody.
		nonce = dst[start : start+nonceLen]
		obfBody := dst[start+nonceLen:]
		dst = append(dst, tag(c.authKey, nonce, obfBody)...)
	}
	return dst, nil
}

// Decode parses a wire frame. It verifies the MAC of authenticated frames and
// rejects tampered or PSK-mismatched ones. It never panics on malformed input.
// The returned frame's payload is a fresh copy, so the caller may reuse raw and
// the Codec's scratch immediately.
//
// Authentication guarantee: a frame is accepted as an authenticated kind
// (CONTROL/PROBE) only if its MAC verifies under the PSK, so tampered or
// PSK-mismatched authenticated frames are rejected. Flipping the (obfuscated)
// kind byte can re-label an authenticated frame as an unauthenticated kind
// (DATA/PARITY), which then decodes without a MAC — this is not a downgrade
// break, because DATA/PARITY are forgeable by design (the inner WireGuard layer
// authenticates the real payload). No mutation can make a frame decode as an
// authentic CONTROL/PROBE.
func (c *Codec) Decode(raw []byte) (Frame, error) {
	// Need at least the nonce plus one body byte (the kind discriminant).
	if len(raw) < nonceLen+1 {
		return nil, fmt.Errorf("%w: %d bytes, need >= %d", ErrMalformed, len(raw), nonceLen+1)
	}

	nonce := raw[:nonceLen]
	rest := raw[nonceLen:]

	// One keystream for the whole decode: init the cipher once, consume the
	// first keystream byte to recover the (obfuscated) kind, then continue the
	// SAME keystream over the remaining body. This avoids the old peekByte's
	// second ChaCha20 init.
	cipher, err := chacha20.NewUnauthenticatedCipher(c.obfKey, nonce)
	if err != nil {
		// obfKey is subkeyLen and nonce is nonceLen, so init cannot fail; a
		// failure indicates a programmer error.
		panic(fmt.Sprintf("frame: chacha20 init: %v", err))
	}
	kindByte := []byte{rest[0]}
	cipher.XORKeyStream(kindByte, kindByte)
	kind := Kind(kindByte[0])
	if !kind.valid() {
		return nil, fmt.Errorf("%w: unknown kind %d", ErrMalformed, uint8(kind))
	}

	obfBody := rest
	if kind.authenticated() {
		if len(rest) < tagLen+1 {
			return nil, fmt.Errorf("%w: authenticated frame too short", ErrMalformed)
		}
		obfBody = rest[:len(rest)-tagLen]
		gotTag := rest[len(rest)-tagLen:]
		wantTag := tag(c.authKey, nonce, obfBody)
		if !hmac.Equal(gotTag, wantTag) {
			return nil, ErrAuth
		}
	}

	// Reconstruct the plaintext body in reusable scratch. Byte 0 is the kind we
	// already recovered; the remaining bytes continue the same keystream.
	c.decScratch = append(c.decScratch[:0], obfBody...)
	body := c.decScratch
	body[0] = kindByte[0]
	if len(body) > 1 {
		cipher.XORKeyStream(body[1:], body[1:])
	}
	return decodeBody(kind, body[1:])
}

// Encode serializes f into a self-contained wire frame under the given PSK. It
// is a convenience wrapper that builds a one-shot Codec; the per-datagram
// datapath uses a long-lived Codec instead (see Codec / defect D5). It fails
// only if the PSK is unset or the system CSPRNG is unavailable.
func Encode(psk config.Key, f Frame) ([]byte, error) {
	c, err := NewCodec(psk)
	if err != nil {
		return nil, err
	}
	return c.Encode(nil, f)
}

// Decode parses a wire frame under the given PSK. It is a convenience wrapper
// that builds a one-shot Codec; hot paths reuse a long-lived Codec instead.
func Decode(psk config.Key, raw []byte) (Frame, error) {
	c, err := NewCodec(psk)
	if err != nil {
		return nil, err
	}
	return c.Decode(raw)
}

// decodeBody parses the header+payload region (the body after the kind byte).
func decodeBody(kind Kind, b []byte) (Frame, error) {
	r := reader{b: b}
	switch kind {
	case KindData:
		seq, e1 := r.u64()
		pathID, e2 := r.u8()
		group, e3 := r.u32()
		fecIndex, e4 := r.u8()
		flags, e5 := r.u8()
		if err := firstErr(e1, e2, e3, e4, e5); err != nil {
			return nil, err
		}
		return Data{OuterSeq: seq, PathID: pathID, FECGroup: group, FECIndex: fecIndex, Flags: flags, Payload: r.rest()}, nil
	case KindParity:
		group, e1 := r.u32()
		idx, e2 := r.u16()
		dataCount, e3 := r.u8()
		pathID, e4 := r.u8()
		if err := firstErr(e1, e2, e3, e4); err != nil {
			return nil, err
		}
		return Parity{FECGroup: group, ParityIndex: idx, DataCount: dataCount, PathID: pathID, Payload: r.rest()}, nil
	case KindProbe:
		pathID, e1 := r.u8()
		probeSeq, e2 := r.u64()
		ts, e3 := r.u64()
		echo, e4 := r.u8()
		sessionID, e5 := r.u64()
		challenge, e6 := r.u64()
		if err := firstErr(e1, e2, e3, e4, e5, e6); err != nil {
			return nil, err
		}
		return Probe{PathID: pathID, ProbeSeq: probeSeq, TimestampNanos: int64(ts), IsEcho: echo != 0, SessionID: sessionID, Challenge: challenge, Payload: r.rest()}, nil
	case KindControl:
		ctype, e1 := r.u8()
		seq, e2 := r.u64()
		if err := firstErr(e1, e2); err != nil {
			return nil, err
		}
		return Control{ControlType: ctype, Seq: seq, Payload: r.rest()}, nil
	default:
		// Unreachable: kind was validated by the caller.
		return nil, fmt.Errorf("%w: unknown kind %d", ErrMalformed, uint8(kind))
	}
}

// subkeys derives the obfuscation and authentication subkeys from the PSK.
func subkeys(psk config.Key) (obfKey, authKey []byte, err error) {
	if !psk.IsSet() {
		return nil, nil, errors.New("frame: PSK is not set")
	}
	secret := psk.Bytes()
	obfKey, err = hkdf.Key(sha256.New, secret[:], nil, infoObf, subkeyLen)
	if err != nil {
		return nil, nil, fmt.Errorf("frame: derive obf key: %w", err)
	}
	authKey, err = hkdf.Key(sha256.New, secret[:], nil, infoAuth, subkeyLen)
	if err != nil {
		return nil, nil, fmt.Errorf("frame: derive auth key: %w", err)
	}
	return obfKey, authKey, nil
}

// obfuscate XORs body in place with the XChaCha20 keystream derived from obfKey
// and nonce. It is its own inverse.
func obfuscate(obfKey, nonce, body []byte) {
	c, err := chacha20.NewUnauthenticatedCipher(obfKey, nonce)
	if err != nil {
		// obfKey is always subkeyLen and nonce is always nonceLen, so the cipher
		// construction cannot fail; a failure indicates a programmer error.
		panic(fmt.Sprintf("frame: chacha20 init: %v", err))
	}
	c.XORKeyStream(body, body)
}

// tag computes the truncated Encrypt-then-MAC authentication tag over
// nonce||obfBody.
func tag(authKey, nonce, obfBody []byte) []byte {
	m := hmac.New(sha256.New, authKey)
	m.Write(nonce)
	m.Write(obfBody)
	return m.Sum(nil)[:tagLen]
}

// reader is a fail-fast big-endian cursor over a byte slice.
type reader struct {
	b   []byte
	off int
}

func (r *reader) need(n int) error {
	if r.off+n > len(r.b) {
		return fmt.Errorf("%w: need %d more bytes at offset %d", ErrMalformed, n, r.off)
	}
	return nil
}

func (r *reader) u8() (uint8, error) {
	if err := r.need(1); err != nil {
		return 0, err
	}
	v := r.b[r.off]
	r.off++
	return v, nil
}

func (r *reader) u16() (uint16, error) {
	if err := r.need(2); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint16(r.b[r.off:])
	r.off += 2
	return v, nil
}

func (r *reader) u32() (uint32, error) {
	if err := r.need(4); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint32(r.b[r.off:])
	r.off += 4
	return v, nil
}

func (r *reader) u64() (uint64, error) {
	if err := r.need(8); err != nil {
		return 0, err
	}
	v := binary.BigEndian.Uint64(r.b[r.off:])
	r.off += 8
	return v, nil
}

// rest returns the remaining (opaque payload) bytes as a fresh copy so the
// decoded frame never aliases the caller's buffer.
func (r *reader) rest() []byte {
	n := len(r.b) - r.off
	if n == 0 {
		r.off = len(r.b)
		return nil
	}
	out := make([]byte, n)
	copy(out, r.b[r.off:])
	r.off = len(r.b)
	return out
}

func firstErr(errs ...error) error {
	for _, e := range errs {
		if e != nil {
			return e
		}
	}
	return nil
}

package bind

import (
	"context"
	"fmt"
	"net"
	"net/netip"
	"strconv"
	"syscall"

	"github.com/7mind/wanbond/internal/config"
)

// listenPath binds one path's UDP socket to port on the path's source.
//
// When dev is non-empty the socket is bound to that INTERFACE (SO_BINDTODEVICE)
// with a wildcard local address instead of pinning the specific source IP. That
// is what makes an edge's path survive a public-IP change mid-session (a re-roam
// / NAT rebind — T16): when the interface's address changes, a device-bound
// socket keeps sending, now sourced from the interface's NEW address, and the far
// side's Bind re-learns that source from the next authenticated probe (T37). A
// socket pinned to the OLD source IP would instead fail every send with
// ENETUNREACH once that address is removed, and the path could never recover
// without a re-Open (which would reset the WireGuard session).
//
// dev is chosen by planPathBinds / selectDeviceBinds and is non-empty ONLY when
// device binding is provably equivalent to pinning the configured source_addr and
// no other path contends for the device (see selectDeviceBinds). When dev is ""
// the socket pins the specific source IP — the pre-T16 behaviour.
//
// Device binding is also BEST-EFFORT even when selected: on Linux <5.7,
// SO_BINDTODEVICE needs CAP_NET_RAW, which the shipped systemd units don't
// grant (CapabilityBoundingSet is CAP_NET_ADMIN only), so a pre-5.7 daemon
// also falls back to source-IP binding; on >=5.7 it needs no capability at
// all (see bindToDevice, pathsock_linux.go, D40). The unit tests bind
// loopback unprivileged too, exercising that same fallback path. It is also
// Linux-only, so a device-bind failure falls back to source-IP binding
// rather than failing Open.
//
// The middle return, deviceErr, is the underlying SO_BINDTODEVICE failure exactly
// when dev != "" and the device bind was attempted and failed (nil when dev == "",
// or when it succeeded) — the fallback fact plus its cause, alongside conn, so a
// caller can log a forced bind="device" path's silent-until-D53 fallback to
// source-IP pinning WITHOUT this file importing internal/log (Open, AddPath, and
// reconcileDeferred are the loggers; this stays logging-free). deviceErr alone does
// NOT mean a fallback socket exists: the caller MUST gate any "fell back to
// source-IP pinning" claim on err == nil (D53 round 2) — deviceErr only says a
// device bind was attempted and failed, not that the source-IP fallback attempted
// here actually produced a working socket.
func listenPath(src netip.Addr, port uint16, dev string) (conn *net.UDPConn, deviceErr error, err error) {
	if dev != "" {
		c, derr := listenOnDevice(src, port, dev)
		if derr == nil {
			return c, nil, nil
		}
		// SO_BINDTODEVICE denied / unsupported: fall back to source-IP binding.
		deviceErr = derr
	}
	laddr := &net.UDPAddr{IP: net.IP(src.AsSlice()), Port: int(port)}
	conn, err = net.ListenUDP("udp", laddr)
	return conn, deviceErr, err
}

// ifaceInfo is the resolution of a source address against the host's interfaces:
// the non-loopback interface currently holding the address (dev, "" when none
// does) and how many addresses of that source's family (IPv4 vs IPv6) the
// interface carries. familyCount drives the device-bind decision — a device-bind
// socket is only equivalent to the configured source pin when the interface holds
// exactly one address of the family.
type ifaceInfo struct {
	dev         string
	familyCount int
}

// planPathBinds resolves every path source against a SINGLE snapshot of the
// host's interfaces and returns the per-path bind plan (see selectDeviceBinds):
// index i holds the device to SO_BINDTODEVICE-bind path i to, or "" to pin path
// i's specific source IP. A snapshot failure resolves every source to an empty
// dev, so all paths (other than a forced BindModeDevice — see selectDeviceBinds)
// fall back to source-IP binding. modes is parallel to srcs and holds each
// path's RESOLVED bind mode (config.Path.Bind after normalize(), I5) — never
// empty on a loaded config, but selectDeviceBinds treats any value other than
// BindModeSource/BindModeDevice as BindModeAuto defensively.
func planPathBinds(srcs []netip.Addr, modes []config.BindMode) []string {
	ifaces, err := net.Interfaces()
	if err != nil {
		ifaces = nil
	}
	return selectDeviceBinds(srcs, modes, func(s netip.Addr) ifaceInfo {
		return interfaceInfo(s, ifaces)
	})
}

// selectDeviceBinds decides, per source address, whether its path socket may be
// bound to the source's interface (SO_BINDTODEVICE + wildcard) or must pin the
// specific source IP, honoring each path's RESOLVED BindMode (I5, Q42):
//
//   - config.BindModeSource forces source-IP pinning unconditionally: the
//     source's interface is never even consulted for a device-bind decision.
//     This is the D38 escape hatch — a source-policy-routed uplink (one address
//     per VLAN interface) that the BindModeAuto heuristic below would otherwise
//     device-bind, silently defeating `ip rule from <source_addr>`.
//
//   - config.BindModeDevice forces a device bind unconditionally: the path's
//     interface is used whenever it resolves, regardless of family count or
//     contention with another configured path. An unresolvable interface (no
//     owning interface found) falls back to source-IP binding; a resolved-but-
//     failing SO_BINDTODEVICE (permission, unsupported) falls back the same way
//     at listenPath's setsockopt layer.
//
//   - config.BindModeAuto (and, defensively, any other/unset value) reproduces
//     the pre-I5 heuristic BYTE-FOR-BYTE: device binding — the T16 roam-
//     surviving mode — is chosen ONLY when it is provably equivalent to pinning
//     the configured source_addr AND no other path contends for the device:
//
//   - the source resolves to a non-loopback interface (dev != ""),
//
//   - that interface carries exactly ONE address of the source's family, so a
//     wildcard-on-device socket can only ever source from the configured address
//     (a multi-address interface would let the kernel pick a DIFFERENT source via
//     route-based selection, voiding source_addr's pin — Criticism 2), and
//
//   - exactly ONE configured path resolves to that interface, because two
//     wildcard+device sockets on the same port and device collide EADDRINUSE;
//     source-IP binding keeps their two DISTINCT specific-IP sockets, which
//     coexist on one port — the pre-T16 behaviour (Criticism 1).
//
// Every auto-mode path that fails those checks falls back to source-IP binding,
// exactly as before T16 (at the cost of not surviving a same-address readdress
// for those paths — the pre-T16 status quo). The returned slice is parallel to
// srcs: a non-empty dev at i means "device-bind path i to it"; "" means
// "source-IP-bind path i". modes is parallel to srcs.
func selectDeviceBinds(srcs []netip.Addr, modes []config.BindMode, resolve func(netip.Addr) ifaceInfo) []string {
	infos := make([]ifaceInfo, len(srcs))
	devPaths := make(map[string]int, len(srcs))
	for i, s := range srcs {
		infos[i] = resolve(s)
		if infos[i].dev != "" {
			devPaths[infos[i].dev]++
		}
	}
	out := make([]string, len(srcs))
	for i := range srcs {
		info := infos[i]
		switch modes[i] {
		case config.BindModeSource:
			// out[i] stays "": never SO_BINDTODEVICE, regardless of what the
			// interface resolution would have decided (the D38 escape hatch).
		case config.BindModeDevice:
			// Forced device-bind: use the path's interface unconditionally when it
			// resolves. info.dev is already "" when unresolvable, which is the
			// fallback-to-source-IP-binding outcome.
			out[i] = info.dev
		default: // config.BindModeAuto, or any other/unset value.
			if info.dev != "" && info.familyCount == 1 && devPaths[info.dev] == 1 {
				out[i] = info.dev
			}
		}
	}
	return out
}

// resolveForcedDeviceBind resolves src's interface for a single, isolated
// forced-device-mode bind (AddPath / the T55 deferred-path reconcile), which —
// unlike Open's planPathBinds/selectDeviceBinds — binds one path at a time with
// no other-path contention to check. It returns "" (source-IP-bind) for any mode
// other than config.BindModeDevice, or when the interface cannot be resolved, so
// the caller's listenPath call falls back to source-IP binding exactly as the
// unresolvable-interface case does in selectDeviceBinds.
//
// It is a thin real-interfaces wrapper around selectForcedDeviceBind (the DECISION,
// split out below — T106 round 2) exactly as planPathBinds wraps selectDeviceBinds:
// the mode check short-circuits BEFORE the net.Interfaces() snapshot so a non-device
// path never pays that syscall.
func resolveForcedDeviceBind(src netip.Addr, mode config.BindMode) string {
	if mode != config.BindModeDevice {
		return ""
	}
	ifaces, err := net.Interfaces()
	if err != nil {
		ifaces = nil
	}
	return selectForcedDeviceBind(src, mode, func(s netip.Addr) ifaceInfo {
		return interfaceInfo(s, ifaces)
	})
}

// selectForcedDeviceBind is resolveForcedDeviceBind's DECISION, split from the
// net.Interfaces() snapshot the same way selectDeviceBinds is split from
// planPathBinds (T106 round 2), so it is unit-testable with a fake resolver and no
// real interfaces: source -> "" (never device-bind, the D38 escape hatch),
// auto/other -> "" HERE (this is the FORCED-device decision only) — a runtime auto path's
// device-bind is now decided separately by Multipath.autoRuntimeDeviceBind, which applies
// Open's selectDeviceBinds contention heuristic over the membership (D30, closed), device+
// resolvable -> the resolved dev, device+unresolvable -> "" (fallback to source-IP binding,
// exactly as selectDeviceBinds' unresolvable case).
func selectForcedDeviceBind(src netip.Addr, mode config.BindMode, resolve func(netip.Addr) ifaceInfo) string {
	if mode != config.BindModeDevice {
		return ""
	}
	return resolve(src).dev
}

// interfaceInfo resolves src against ifaces (a single net.Interfaces snapshot):
// it returns the non-loopback interface that currently owns src and the count of
// same-family addresses on it. A loopback/unspecified/invalid src, or no owning
// interface, yields an empty dev (familyCount 0). It is the resolution step that
// lets a source-address config select a device to bind, so the socket can outlive
// that address changing.
func interfaceInfo(src netip.Addr, ifaces []net.Interface) ifaceInfo {
	if !src.IsValid() || src.IsLoopback() || src.IsUnspecified() {
		return ifaceInfo{}
	}
	want := src.Unmap()
	for _, ifc := range ifaces {
		if ifc.Flags&net.FlagLoopback != 0 {
			continue
		}
		addrs, err := ifc.Addrs()
		if err != nil {
			continue
		}
		ips := make([]netip.Addr, 0, len(addrs))
		for _, a := range addrs {
			ipn, ok := a.(*net.IPNet)
			if !ok {
				continue
			}
			ip, ok := netip.AddrFromSlice(ipn.IP)
			if !ok {
				continue
			}
			ips = append(ips, ip)
		}
		familyCount, owns := familyBindCount(want, ips)
		if owns {
			return ifaceInfo{dev: ifc.Name, familyCount: familyCount}
		}
	}
	return ifaceInfo{}
}

// familyBindCount reports, for a source address want, how many of an interface's
// addresses count toward the device-bind equivalence decision (see
// selectDeviceBinds) and whether want itself is present. familyCount must equal 1
// for a device-bind to be provably equivalent to pinning want: it counts the
// same-family addresses the kernel could otherwise source-select from.
//
// For a GLOBAL (non-link-local) v6 source, fe80::/10 link-local addresses are
// EXCLUDED from the count: an up interface virtually always carries a kernel
// link-local alongside its configured global v6 address, but the kernel never
// source-selects a link-local for a global destination, so a link-local co-resident
// does not void the global source_addr pin — a wildcard+device socket still sources
// only from the configured global address (defect D13). For a v4 source or a
// link-local v6 source every same-family address is counted, unchanged: a
// link-local-only interface, and any v4 interface, is unaffected.
func familyBindCount(want netip.Addr, addrs []netip.Addr) (familyCount int, owns bool) {
	excludeLinkLocal := !want.Is4() && !want.IsLinkLocalUnicast()
	for _, ip := range addrs {
		ip = ip.Unmap()
		if ip.Is4() == want.Is4() && (!excludeLinkLocal || !ip.IsLinkLocalUnicast()) {
			familyCount++
		}
		if ip == want {
			owns = true
		}
	}
	return familyCount, owns
}

// listenOnDevice binds a UDP socket to the family-matched wildcard address on port
// and pins it to dev via SO_BINDTODEVICE (bindToDevice, platform-specific). It
// returns an error the caller treats as "fall back to source-IP binding".
func listenOnDevice(src netip.Addr, port uint16, dev string) (*net.UDPConn, error) {
	host, network := "0.0.0.0", "udp4"
	if !src.Is4() && !src.Is4In6() {
		host, network = "::", "udp6"
	}
	lc := net.ListenConfig{
		Control: func(_, _ string, c syscall.RawConn) error {
			var operr error
			if err := c.Control(func(fd uintptr) { operr = bindToDevice(fd, dev) }); err != nil {
				return err
			}
			return operr
		},
	}
	pc, err := lc.ListenPacket(context.Background(), network, net.JoinHostPort(host, strconv.Itoa(int(port))))
	if err != nil {
		return nil, err
	}
	uc, ok := pc.(*net.UDPConn)
	if !ok {
		_ = pc.Close()
		return nil, fmt.Errorf("bind: device %q listener is %T, want *net.UDPConn", dev, pc)
	}
	return uc, nil
}

package bind

import (
	"testing"

	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
)

// TestInnerMTUFixture pins the inner-MTU arithmetic to a fixture so a change to
// any overhead term is caught. For a 1500-byte IPv4 path with FEC off:
//
//	1500 − (20+8 IP/UDP) − 40 outer DATA frame − (16+16 WG) = 1400.
func TestInnerMTUFixture(t *testing.T) {
	if frame.DataOverhead != 40 {
		t.Fatalf("frame.DataOverhead = %d, want 40 (nonce 24 + kind 1 + seq 8 + path 1 + group 4 + fec-index 1 + flags 1)", frame.DataOverhead)
	}

	const (
		pathMTU = 1500
		// 1500 - 28 - 40 - 32
		wantInner = 1400
	)
	if got := InnerMTU(pathMTU, false); got != wantInner {
		t.Fatalf("InnerMTU(%d, fec=false) = %d, want %d", pathMTU, got, wantInner)
	}

	// Cross-check: the sum of all overheads plus the inner MTU must equal the
	// path MTU exactly (no slack, no fragmentation).
	overhead := IPv4UDPOverhead + frame.DataOverhead + WGTransportOverhead
	if InnerMTU(pathMTU, false)+overhead != pathMTU {
		t.Fatalf("inner (%d) + overhead (%d) = %d, want path MTU %d",
			InnerMTU(pathMTU, false), overhead, InnerMTU(pathMTU, false)+overhead, pathMTU)
	}

	// IPv6 underlay costs 20 bytes more of IP header.
	if got := InnerMTU6(pathMTU, false); got != wantInner-20 {
		t.Fatalf("InnerMTU6(%d, fec=false) = %d, want %d", pathMTU, got, wantInner-20)
	}

	// With FEC on, the inner MTU is a further FECParityMTUPenalty smaller so a full-size
	// parity frame also fits (T24). The penalty is exactly 5 for this wire layout.
	if FECParityMTUPenalty != 5 {
		t.Fatalf("FECParityMTUPenalty = %d, want 5 (parity overhead + shard framing + seq prefix − data overhead)", FECParityMTUPenalty)
	}
	if got := InnerMTU(pathMTU, true); got != wantInner-FECParityMTUPenalty {
		t.Fatalf("InnerMTU(%d, fec=true) = %d, want %d", pathMTU, got, wantInner-FECParityMTUPenalty)
	}
}

// TestParityFrameFitsPathMTUWithFEC is the fix witness for the parity-exceeds-MTU
// defect: at the FEC-aware inner MTU, a full-size DATA frame's group PARITY frame must
// fit the path MTU on the wire. Under the pre-fix budget (which reserved nothing for
// parity) the parity frame exceeded the path MTU by exactly FECParityMTUPenalty and
// IP-fragmented / PMTUD-blackholed. The parity wire size is computed from the real
// codec + FEC shard geometry, not restated, so a framing change cannot pass vacuously.
func TestParityFrameFitsPathMTUWithFEC(t *testing.T) {
	const pathMTU = 1500
	inner := InnerMTU(pathMTU, true)

	// The largest inner (WG) payload a DATA frame carries at this inner MTU: the TUN's
	// inner IP packet plus WireGuard's own transport overhead.
	maxWGPayload := inner + WGTransportOverhead

	// The FEC data shard coded bytes are fecSeqPrefixLen + the WG payload; a parity
	// shard's wire payload is the codec's length prefix + that shard length. The parity
	// FRAME wire size is the PARITY outer framing + the parity shard payload.
	shardLen := fec.ShardFramingOverhead + fecSeqPrefixLen + maxWGPayload
	parityWire := frame.ParityOverhead + shardLen

	// The outer datagram (parity frame) plus IP/UDP must fit the path MTU.
	if got := parityWire + IPv4UDPOverhead; got > pathMTU {
		t.Fatalf("full-size PARITY on-wire = %d (+IP/UDP), exceeds path MTU %d by %d — parity would fragment", got, pathMTU, got-pathMTU)
	}

	// And a full-size DATA frame must still fit too (the penalty did not over-reserve).
	dataWire := frame.DataOverhead + maxWGPayload
	if got := dataWire + IPv4UDPOverhead; got > pathMTU {
		t.Fatalf("full-size DATA on-wire = %d (+IP/UDP), exceeds path MTU %d", got, pathMTU)
	}
}

// TestDataOverheadMatchesEncoding confirms DataOverhead equals the real wire cost
// of a zero-payload DATA frame, so the MTU budget can never silently drift from
// the codec.
func TestDataOverheadMatchesEncoding(t *testing.T) {
	psk := testKey(t, 0x01)
	raw, err := frame.Encode(psk, frame.Data{})
	if err != nil {
		t.Fatalf("encode empty DATA: %v", err)
	}
	if len(raw) != frame.DataOverhead {
		t.Fatalf("empty DATA frame is %d bytes on the wire, but frame.DataOverhead = %d", len(raw), frame.DataOverhead)
	}
}

	defer g.mu.Unlock()
	if a.Configured() {
		if g.configLive || g.plainLive > 0 {
			return fmt.Errorf("device: refusing to start an amnezia-configured engine while another engine is live: " +
				"amneziawg-go keeps the magic-header message types in process-global state and resets them to defaults on ANY engine's Close, " +
				"so a configured engine requires process exclusivity — at most one, with no other engine alongside it (D2)")
		}
		g.configLive = true
		return nil
	}
	if g.configLive {
		return fmt.Errorf("device: refusing to start a second engine while an amnezia-configured engine is live: " +
			"closing this engine would reset amneziawg-go's process-global message types to defaults under the live amnezia tunnel (D2)")
	}
	g.plainLive++
	return nil
}

// release drops an engine's hold on the guard. A configured engine clears the
// single configured slot; a plain engine decrements the live plain count.
func (g *amneziaGuard) release(a config.Amnezia) {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		g.configLive = false
		return
	}
	if g.plainLive > 0 {
		g.plainLive--
	}
}

// Up creates the TUN, wires the multipath Bind into the amneziawg engine,
// applies the crypto configuration from cfg, and brings the device up. The same
// path drives both roles; the role only changes which UAPI fields cfg carries
// (the concentrator sets listen_port; the edge sets each peer's endpoint).
func Up(cfg *config.Config, lg log.Logger) (*Tunnel, error) {
	clg := lg.Component("device")

	tunDev, err := tun.CreateTUN(defaultTUNName, tunMTU(cfg))
	if err != nil {
